// Sasha at Twilo - Late Night Progressive
// 132 BPM | G minor | Deep, hypnotic, filtered

let kickVol = slider(0.8, 0, 1, 0.01, "Kick")
let bassVol = slider(0.6, 0, 1, 0.01, "Bass")
let hatVol = slider(0.35, 0, 1, 0.01, "Hats")
let arpVol = slider(0.45, 0, 1, 0.01, "Arp")
let padVol = slider(0.55, 0, 1, 0.01, "Pad")
let leadVol = slider(0, 0, 1, 0.01, "Lead")
let filterPos = slider(1500, 200, 4000, 10, "Filter")

setcps(132/60/4)

let kick = stack(
  s("bd").bank("RolandTR909").struct("x x x x"),
  s("cp").bank("RolandTR909").struct("~ x ~ x")
).gain(kickVol)

let bass = note("<g2 g2 eb2 eb2 bb2 bb2 f2 f2>")
  .struct("x ~ [~ x] x ~ x [~ x] ~")
  .s("sawtooth")
  .cutoff(perlin.range(250, 1200).slow(16))
  .resonance(14)
  .decay(0.2).sustain(0.08).release(0.3)
  .gain(bassVol)
  .room(0.25)

let hats = s("hh*8").bank("RolandTR707")
  .gain(hatVol)
  .room(0.15)

let arp = note("g4 d5 bb4 g5 d5 bb4 f5 d5")
  .s("triangle")
  .cutoff(perlin.range(600, 2800).slow(12))
  .decay(0.12).sustain(0.03).release(0.35)
  .delay(0.4).delaytime(3/8).delayfeedback(0.5)
  .gain(arpVol)
  .room(0.5)

let pad = note("<[g3,bb3,d4] [g3,bb3,d4] [g3,bb3,eb4] [g3,bb3,eb4] [f3,bb3,d4] [f3,bb3,d4] [f3,a3,c4] [f3,a3,c4]>")
  .s("sawtooth")
  .cutoff(perlin.range(300, 1800).slow(24))
  .resonance(5)
  .attack(1.0).decay(0.5).sustain(0.7).release(2.0)
  .vowel("<a a e e i i o o>")
  .room(0.85).size(0.9)
  .jux(rev)
  .gain(padVol)

let lead = note("g4 ~ bb4 ~ d5 ~ c5 bb4 ~ a4 ~ g4 ~ f4 d4 ~").slow(2)
  .s("sawtooth")
  .superimpose(x => x.add(0.08))
  .superimpose(x => x.add(-0.08))
  .cutoff(filterPos)
  .resonance(8)
  .decay(0.3).sustain(0.15).release(0.8)
  .delay(0.4).delaytime(3/8).delayfeedback(0.55)
  .room(0.7).size(0.8)
  .jux(rev)
  .gain(leadVol)

stack(kick, bass, hats, arp, pad, lead)
